+        if (shadows) {
+            // Generate unique shadow name
+            self.shadow_counter += 1;
+            const rename = try std.fmt.allocPrint(self.allocator, "__shadow_{s}_{d}", .{ var_name, self.shadow_counter });
+            shadow_rename = rename;
+        }
