+        try analysis.variables.put(var_name, .{
+            .name = var_name,
+            .declared_at = position,
+            .used_after_decl = false,
+            .assigned_to = true,
+            .captured = false,
+            .shadows_outer = shadows,
+            .shadow_rename = shadow_rename,
+        });
